using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using HRCloud.Libs;
using OpenQA.Selenium.Appium;
using OpenQA.Selenium.Appium.iOS;
using HRCloud.Actions;
using HRCloud.Interfaces;
using OpenQA.Selenium.Appium.Android;

namespace HRCloud.Tests.App
{
    [TestClass]
    [Obsolete]
    public class TestBase_App
    {
        public TestContext TestContext { get; set; }

        [AssemblyInitialize]
        [Obsolete]
        public static void BeforeRun(TestContext tc)
        {
            string userName = System.Security.Principal.WindowsIdentity.GetCurrent().Name;
            globalVars.download_path = @"C:\Users\"+ userName.Split('\\')[1] + @"\Downloads\";

            globalVars.platformName = tc.Properties["platformName"].ToString().ToUpper();

            if (globalVars.platformName == "IOS" || globalVars.platformName == "ANDROID")
            {
                string deviceName = tc.Properties["deviceName"].ToString();
                string appium_server = tc.Properties["appium_server"].ToString();
                string appium_port = tc.Properties["appium_port"].ToString();

                globalVars.capability = new AppiumOptions();
                if (globalVars.platformName == "IOS")
                {
                    string platformVersion = tc.Properties["platformVersion"].ToString();
                    string udid = tc.Properties["udid"].ToString();
                    globalVars.capability.AddAdditionalCapability("platformName", "iOS");
                    globalVars.capability.AddAdditionalCapability("deviceName", deviceName);
                    globalVars.capability.AddAdditionalCapability("platformVersion", platformVersion);
                    globalVars.capability.AddAdditionalCapability("udid", udid);
                    globalVars.capability.AddAdditionalCapability("bundleId", "com.hrcloud.Workmates");
                    globalVars.capability.AddAdditionalCapability("xcodeOrgId", "CCW243364G");
                    globalVars.capability.AddAdditionalCapability("xcodeSigningId", "iPhone Developer");
                    //globalVars.capability.AddAdditionalCapability("xcodeSigningId", "Dev HRCloud");
                    globalVars.capability.AddAdditionalCapability("automationName", "XCUITest");
                    globalVars.capability.AddAdditionalCapability("useNewWDA", "true");
                    globalVars.capability.AddAdditionalCapability("startIWDP", "true");
                }
                else if (globalVars.platformName == "ANDROID")
                {
                    globalVars.capability.AddAdditionalCapability("platformName", "Android");
                    globalVars.capability.AddAdditionalCapability("deviceName", deviceName);
                    globalVars.capability.AddAdditionalCapability("appPackage", "neogov.workmates");
                    globalVars.capability.AddAdditionalCapability("appActivity", "neogov.workmates.shared.infrastructure.framework.ActivityStartup");
                    globalVars.capability.AddAdditionalCapability("newCommandTimeout", 300);
                    //globalVars.capability.AddAdditionalCapability("appActivity", "neogov.workmates.share.activity.StartActivity");
                    globalVars.capability.AddAdditionalCapability("noReset", "true");
                }
                globalVars.appium_server = new Uri(String.Format("http://{0}:{1}/wd/hub", appium_server, appium_port));

                if (globalVars.platformName == "IOS")
                {
                    globalVars.ios_device_driver = new IOSDriver(globalVars.appium_server, globalVars.capability, TimeSpan.FromMinutes(3));
                    globalVars.ios_device_driver.Manage().Timeouts().ImplicitWait = TimeSpan.FromSeconds(constant.short_wait);
                }
                else
                {
                    globalVars.android_device_driver = new AndroidDriver(globalVars.appium_server, globalVars.capability);
                    globalVars.android_device_driver.Manage().Timeouts().ImplicitWait = TimeSpan.FromSeconds(constant.short_wait);
                }

            }
        }

        [AssemblyCleanup]
        static public void AssemblyCleanup()
        {
            if (globalVars.platformName == "IOS")
                globalVars.ios_device_driver.Quit();
            else if (globalVars.platformName == "ANDROID")
                globalVars.android_device_driver.Quit();
        }

        [TestInitialize]

        public void Setup()
        {
            if (!General.ContinueRunTest(TestContext.DataRow["Priority"].ToString(), TestContext.Properties["min_data_priority"].ToString()))
               Assert.Inconclusive("This data's priority is lower than min priority for data. Please check the test setting!");
            if (globalVars.platformName == "IOS")
                Actions.App.ResetIOS();
            else
                Actions.App.ResetAndroid();

            globalVars.TestResultFolder = TestContext.TestResultsDirectory;
            globalVars.TestCaseName = TestContext.TestName;
        }

        [TestCleanup]
        public void Teardown()
        {
            if (globalVars.platformName == "IOS")
                globalVars.ios_device_driver.CloseApp();
            else
                globalVars.android_device_driver.CloseApp();
        }
    }
}

